import ts from"typescript";import{isFile}from"./fs.js";import{dirname}from"./path.js";export const loadTSConfig=async i=>{if(isFile(i)){const s=ts.readConfigFile(i,ts.sys.readFile),e=ts.parseJsonConfigFileContent(s.config,ts.sys,dirname(i));return{isFile:!0,compilerOptions:e.options??{},fileNames:e.fileNames}}return{isFile:!1,compilerOptions:{},fileNames:[]}};